(function() {
  const inputs = Array.from(document.querySelectorAll('input'));
  const searchInput = inputs.find(i => i.placeholder.toLowerCase().includes('search') || i.placeholder.toLowerCase().includes('filter'));
  if (searchInput) {
    searchInput.focus();
    searchInput.value = 'Ethan Strait';
    searchInput.dispatchEvent(new Event('input', { bubbles: true }));
    searchInput.dispatchEvent(new Event('change', { bubbles: true }));
    return "Typed into search box";
  }
  return "Search box not found";
})()

(function() {
  const input = document.getElementById('_weave_e_10');
  if (input) {
    input.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', bubbles: true }));
    input.dispatchEvent(new KeyboardEvent('keypress', { key: 'Enter', bubbles: true }));
    input.dispatchEvent(new KeyboardEvent('keyup', { key: 'Enter', bubbles: true }));
    return "Pressed Enter";
  }
  return "Input not found";
})()

